     5→//! Saddle command - Return context needed to saddle up on a Heat
     6→
     7→use std::fs;
     8→use std::path::PathBuf;
     9→
    10→use crate::jjrf_favor::jjrf_Firemark as Firemark;
    11→use crate::jjrg_gallops::{jjrg_Gallops as Gallops, jjrg_HeatStatus as HeatStatus, jjrg_PaceState as PaceState};
    12→use crate::jjrp_print::{jjrp_Table, jjrp_Column, jjrp_Align};
    13→use crate::jjrs_steeplechase::{jjrs_get_entries, jjrs_ReinArgs};
    14→use crate::jjrq_query::jjrq_resolve_default_heat;
    15→use crate::jjrc_core::jjrc_timestamp_full;
    16→use crate::jjrn_notch::jjrn_format_session_message;
    17→
    18→/// Arguments for saddle command
    19→#[derive(clap::Args, Debug)]
    20→pub struct jjrsd_SaddleArgs {
    21→    /// Path to the Gallops JSON file
    22→    #[arg(long, short = 'f', default_value = ".claude/jjm/jjg_gallops.json")]
    23→    pub file: PathBuf,
    24→
    25→    /// Target Heat identity (Firemark). If omitted, uses first racing heat.
    26→    pub firemark: Option<String>,
    27→}
    28→
    29→/// Run the saddle command - return Heat context
    30→pub async fn jjrsd_run_saddle(args: jjrsd_SaddleArgs) -> i32 {
    31→    let gallops = match Gallops::jjrg_load(&args.file) {
    32→        Ok(g) => g,
    33→        Err(e) => {
    34→            eprintln!("jjx_saddle: error: {}", e);
    35→            return 1;
    36→        }
    37→    };
    38→
    39→    // Collect racing heats and display summary table
    40→    {
    41→        let mut racing_heats: Vec<(&String, &crate::jjrg_gallops::jjrg_Heat)> = gallops.heats.iter()
    42→            .filter(|(_, heat)| heat.status == HeatStatus::Racing)
    43→            .collect();
    44→
    45→        // Sort by key for stability
    46→        racing_heats.sort_by(|a, b| a.0.cmp(b.0));
    47→
    48→        if !racing_heats.is_empty() {
    49→            let mut table = jjrp_Table::jjrp_new(vec![
    50→                jjrp_Column::new("₣Fire", jjrp_Align::Left),
    51→                jjrp_Column::new("Silks", jjrp_Align::Left),
    52→                jjrp_Column::new("Status", jjrp_Align::Left),
    53→                jjrp_Column::new("Done", jjrp_Align::Right),
    54→                jjrp_Column::new("Total", jjrp_Align::Right),
    55→            ]);
    56→
    57→            // Measure all rows to compute column widths
    58→            for (key, heat) in &racing_heats {
    59→                let defined_count = heat.paces.values().filter(|pace| {
    60→                    if let Some(tack) = pace.tacks.first() {
    61→                        tack.state != PaceState::Abandoned
    62→                    } else {
    63→                        true
    64→                    }
    65→                }).count();
    66→
    67→                let completed_count = heat.paces.values().filter(|pace| {
    68→                    if let Some(tack) = pace.tacks.first() {
    69→                        tack.state == PaceState::Complete
    70→                    } else {
    71→                        false
    72→                    }
    73→                }).count();
    74→
    75→                table.jjrp_measure(&[
    76→                    key,
    77→                    &heat.silks,
    78→                    "racing",
    79→                    &completed_count.to_string(),
    80→                    &defined_count.to_string(),
    81→                ]);
    82→            }
    83→
    84→            // Print header and separator
    85→            println!("Racing-heats:");
    86→            table.jjrp_print_header();
    87→            table.jjrp_print_separator();
    88→
    89→            // Print data rows
    90→            for (key, heat) in &racing_heats {
    91→                let defined_count = heat.paces.values().filter(|pace| {
    92→                    if let Some(tack) = pace.tacks.first() {
    93→                        tack.state != PaceState::Abandoned
    94→                    } else {
    95→                        true
    96→                    }
    97→                }).count();
    98→
    99→                let completed_count = heat.paces.values().filter(|pace| {
   100→                    if let Some(tack) = pace.tacks.first() {
   101→                        tack.state == PaceState::Complete
   102→                    } else {
   103→                        false
   104→                    }
   105→                }).count();
   106→
   107→                table.jjrp_print_row(&[
   108→                    key,
   109→                    &heat.silks,
   110→                    "racing",
   111→                    &completed_count.to_string(),
   112→                    &defined_count.to_string(),
   113→                ]);
   114→            }
   115→
   116→            println!();
   117→        }
   118→    }
   119→
   120→    // Resolve firemark: use provided value or auto-select first racing heat
   121→    let firemark_str = match args.firemark {
   122→        Some(fm) => fm,
   123→        None => {
   124→            match jjrq_resolve_default_heat(&gallops) {
   125→                Ok(fm) => fm,
   126→                Err(e) => {
   127→                    eprintln!("jjx_saddle: error: {}", e);
   128→                    return 1;
   129→                }
   130→            }
   131→        }
   132→    };
   133→
   134→    let firemark = match Firemark::jjrf_parse(&firemark_str) {
   135→        Ok(fm) => fm,
   136→        Err(e) => {
   137→            eprintln!("jjx_saddle: error: {}", e);
   138→            return 1;
   139→        }
   140→    };
   141→
   142→    let heat_key = firemark.jjrf_display();
   143→    let heat = match gallops.heats.get(&heat_key) {
   144→        Some(h) => h,
   145→        None => {
   146→            eprintln!("jjx_saddle: error: Heat '{}' not found", heat_key);
   147→            return 1;
   148→        }
   149→    };
   150→
   151→    // Check if heat is stabled (cannot saddle stabled heat)
   152→    if heat.status == HeatStatus::Stabled {
   153→        eprintln!("jjx_saddle: error: Cannot saddle stabled heat '{}'", heat_key);
   154→        return 1;
   155→    }
   156→
   157→    // Read paddock file content
   158→    let paddock_content = match fs::read_to_string(&heat.paddock_file) {
   159→        Ok(content) => content,
   160→        Err(e) => {
   161→            eprintln!("jjx_saddle: error reading paddock file '{}': {}", heat.paddock_file, e);
   162→            return 1;
   163→        }
   164→    };
   165→
   166→    // Get recent steeplechase entries
   167→    let recent_work = jjrs_get_entries(&jjrs_ReinArgs {
   168→        firemark: firemark.jjrf_as_str().to_string(),
   169→        limit: 10,
   170→    }).unwrap_or_default();
   171→
   172→    // Find first actionable pace (rough or bridled)
   173→    let mut pace_coronet: Option<String> = None;
   174→    let mut pace_silks: Option<String> = None;
   175→    let mut pace_state: Option<String> = None;
   176→    let mut spec: Option<String> = None;
   177→    let mut direction: Option<String> = None;
   178→
   179→    for coronet_key in &heat.order {
   180→        if let Some(pace) = heat.paces.get(coronet_key) {
   181→            if let Some(tack) = pace.tacks.first() {
   182→                match tack.state {
   183→                    PaceState::Rough | PaceState::Bridled => {
   184→                        pace_coronet = Some(coronet_key.clone());
   185→                        pace_silks = Some(tack.silks.clone());
   186→                        pace_state = Some(match tack.state {
   187→                            PaceState::Rough => "rough".to_string(),
   188→                            PaceState::Bridled => "bridled".to_string(),
   189→                            _ => unreachable!(),
   190→                        });
   191→                        spec = Some(tack.text.clone());
   192→                        if tack.state == PaceState::Bridled {
   193→                            direction = tack.direction.clone();
   194→                        }
   195→                        break;
   196→                    }
   197→                    _ => continue,
   198→                }
   199→            }
   200→        }
   201→    }
   202→
   203→    // Determine heat status string
   204→    let status_str = match heat.status {
   205→        HeatStatus::Racing => "racing",
   206→        HeatStatus::Stabled => "stabled",
   207→        HeatStatus::Retired => "retired",
   208→    };
   209→
   210→    // Output plain text format
   211→    println!("Heat: {} ({}) [{}]", heat.silks, heat_key, status_str);
   212→    println!("Paddock: {}", heat.paddock_file);
   213→    println!();
   214→    println!("Paddock-content:");
   215→    for line in paddock_content.lines() {
   216→        println!("  {}", line);
   217→    }
   218→    println!();
   219→
   220→    if let Some(coronet) = pace_coronet {
   221→        if let Some(silks) = pace_silks {
   222→            if let Some(state) = pace_state {
   223→                println!("Next: {} ({}) [{}]", silks, coronet, state);
   224→                println!();
   225→                if let Some(spec_text) = spec {
   226→                    println!("Spec:");
   227→                    for line in spec_text.lines() {
   228→                        println!("  {}", line);
   229→                    }
   230→                    println!();
   231→                }
   232→                if let Some(dir_text) = direction {
   233→                    println!("Direction:");
   234→                    for line in dir_text.lines() {
   235→                        println!("  {}", line);
   236→                    }
   237→                    println!();
   238→                }
   239→            }
   240→        }
   241→    }
   242→
   243→    // Output recent work table
   244→    // Filter entries to only show action codes 'n' (notch), 'A' (approach), 'd' (discussion)
   245→    let filtered_work: Vec<_> = recent_work.iter().filter(|entry| {
   246→        if let Some(ref action) = entry.action {
   247→            action == "n" || action == "A" || action == "d"
   248→        } else {
   249→            false
   250→        }
   251→    }).collect();
   252→
   253→    if !filtered_work.is_empty() {
   254→        println!("Recent-work:");
   255→
   256→        let mut table = jjrp_Table::jjrp_new(vec![
   257→            jjrp_Column::new("Commit", jjrp_Align::Left),
   258→            jjrp_Column::new("Identity", jjrp_Align::Left),
   259→            jjrp_Column::new("Subject", jjrp_Align::Left),
   260→        ]);
   261→
   262→        // Measure all rows to compute column widths
   263→        for entry in &filtered_work {
   264→            let identity_str = if let Some(ref coronet) = entry.coronet {
   265→                coronet.clone()
   266→            } else {
   267→                heat_key.clone()
   268→            };
   269→            table.jjrp_measure(&[
   270→                &entry.commit,
   271→                &identity_str,
   272→                &entry.subject,
   273→            ]);
   274→        }
   275→
   276→        // Print header and separator
   277→        table.jjrp_print_header();
   278→        table.jjrp_print_separator();
   279→
   280→        // Print data rows
   281→        for entry in &filtered_work {
   282→            let identity_str = if let Some(ref coronet) = entry.coronet {
   283→                coronet.clone()
   284→            } else {
   285→                heat_key.clone()
   286→            };
   287→            table.jjrp_print_row(&[
   288→                &entry.commit,
   289→                &identity_str,
   290→                &entry.subject,
   291→            ]);
   292→        }
   293→    }
   294→
   295→    // Check if session probe is needed (gap > 1 hour or no commits)
   296→    let last_timestamp = recent_work.first().map(|e| e.timestamp.as_str());
   297→    if crate::jjrc_core::jjrc_needs_session_probe(last_timestamp) {
   298→        println!();
   299→        match vvc::vvcp_probe().await {
   300→            Ok(probe_result) => {
   301→                // Get timestamp for session marker
   302→                let timestamp = jjrc_timestamp_full();
   303→
   304→                // Build commit message: subject + body
   305→                let subject = jjrn_format_session_message(&firemark, &timestamp);
   306→                let message = format!("{}\n\n{}", subject, probe_result);
   307→
   308→                // Create session chalk commit (allow_empty: true, no_stage: true)
   309→                let commit_args = vvc::vvcc_CommitArgs {
   310→                    prefix: None,
   311→                    message: Some(message),
   312→                    allow_empty: true,
   313→                    no_stage: true,
   314→                    size_limit: vvc::VVCG_SIZE_LIMIT,
   315→                    warn_limit: vvc::VVCG_WARN_LIMIT,
   316→                };
   317→
   318→                match vvc::commit(&commit_args) {
   319→                    0 => {
   320→                        // Get the commit hash of HEAD
   321→                        if let Ok(output) = std::process::Command::new("git")
   322→                            .args(["rev-parse", "--short", "HEAD"])
   323→                            .output()
   324→                        {
   325→                            if output.status.success() {
   326→                                let commit_hash = String::from_utf8_lossy(&output.stdout).trim().to_string();
   327→                                println!("Session-marker: {} ({})", commit_hash, timestamp);
   328→                            } else {
   329→                                println!("Session-marker: created ({})", timestamp);
   330→                            }
   331→                        } else {
   332→                            println!("Session-marker: created ({})", timestamp);
   333→                        }
   334→                    }
   335→                    _ => {
   336→                        eprintln!("jjx_saddle: warning: failed to create session marker commit");
   337→                    }
   338→                }
   339→            }
   340→            Err(e) => {
   341→                eprintln!("jjx_saddle: warning: probe failed: {}", e);
   342→            }
   343→        }
   344→    }
   345→
   346→    0
   347→}
