     5→//! JJK Core - shared infrastructure
     6→//!
     7→//! Common utilities used across JJK modules.
     8→
     9→#![allow(non_camel_case_types)]
    10→
    11→use std::path::PathBuf;
    12→use chrono::Local;
    13→
    14→/// Default path to the Gallops JSON file
    15→pub const JJRC_DEFAULT_GALLOPS_PATH: &str = ".claude/jjm/jjg_gallops.json";
    16→
    17→/// Get the default Gallops file path relative to repo root
    18→pub fn jjrc_default_gallops_path() -> PathBuf {
    19→    PathBuf::from(JJRC_DEFAULT_GALLOPS_PATH)
    20→}
    21→
    22→/// Generate timestamp in YYMMDD format
    23→pub fn jjrc_timestamp_date() -> String {
    24→    Local::now().format("%y%m%d").to_string()
    25→}
    26→
    27→/// Generate timestamp in YYMMDD-HHMM format
    28→pub fn jjrc_timestamp_full() -> String {
    29→    Local::now().format("%y%m%d-%H%M").to_string()
    30→}
    31→
    32→/// Get creation date from BUD_NOW_STAMP env var, or fall back to system clock
    33→///
    34→/// If BUD_NOW_STAMP is set (format: YYYYMMDD-HHMMSS-PID-RANDOM),
    35→/// extract YYYYMMDD and convert to YYMMDD (drop century).
    36→/// Otherwise, use jjrc_timestamp_date() for current system clock.
    37→pub fn jjrc_timestamp_from_env() -> String {
    38→    match std::env::var("BUD_NOW_STAMP") {
    39→        Ok(stamp) => {
    40→            // Expected format: YYYYMMDD-HHMMSS-PID-RANDOM
    41→            // Extract YYYYMMDD and convert to YYMMDD by dropping first 2 digits
    42→            if stamp.len() >= 8 {
    43→                let yyyymmdd = &stamp[..8];
    44→                // Drop century (first 2 chars) to get YYMMDD
    45→                if let Ok(year) = yyyymmdd[..4].parse::<u32>() {
    46→                    let yy = year % 100;
    47→                    let mmdd = &yyyymmdd[4..];
    48→                    return format!("{:02}{}", yy, mmdd);
    49→                }
    50→            }
    51→            // Fall back to system clock if parsing fails
    52→            jjrc_timestamp_date()
    53→        }
    54→        Err(_) => {
    55→            // BUD_NOW_STAMP not set, use system clock
    56→            jjrc_timestamp_date()
    57→        }
    58→    }
    59→}
    60→
    61→/// Check if a session probe is needed based on time gap from last commit
    62→///
    63→/// Returns true if:
    64→/// - No timestamp provided (no commits in steeplechase), OR
    65→/// - Gap from last_timestamp to now is > 1 hour
    66→///
    67→/// Timestamp format expected: "YYYY-MM-DD HH:MM"
    68→pub fn jjrc_needs_session_probe(last_timestamp: Option<&str>) -> bool {
    69→    use chrono::NaiveDateTime;
    70→
    71→    let Some(ts) = last_timestamp else {
    72→        // No commits in steeplechase - new session
    73→        return true;
    74→    };
    75→
    76→    // Parse timestamp: "YYYY-MM-DD HH:MM" -> NaiveDateTime
    77→    let parsed = NaiveDateTime::parse_from_str(&format!("{}:00", ts), "%Y-%m-%d %H:%M:%S");
    78→    let Ok(last_time) = parsed else {
    79→        // If we can't parse the timestamp, assume new session
